minimalFix:
To fix the issue, you need to pass the same `options` object (specifically `{ passive: true }`) to `window.removeEventListener` as was used for `window.addEventListener`. This ensures the browser can correctly identify and unregister the event listener.

```typescript
// src/hooks/useScrollAnalytics.ts
import { useEffect } from 'react';
import { AnalyticsService } from '../services/AnalyticsService';

export function useScrollAnalytics(
  pageId: string,
  analyticsService: AnalyticsService
): void {
  useEffect(() => {
    const onScroll = () => {
      const scrollHeight = document.body.scrollHeight - window.innerHeight;
      const depth = scrollHeight > 0
        ? Math.round((window.scrollY / scrollHeight) * 100)
        : 0;
      analyticsService.track('scroll_depth', { pageId, depth });
    };

    const scrollOptions = { passive: true }; // Define options once

    window.addEventListener('scroll', onScroll, scrollOptions);

    // Pass the same options object to removeEventListener
    return () => window.removeEventListener('scroll', onScroll, scrollOptions);
  }, [pageId, analyticsService]);
}
```
